// This code extracts the ID from a Google Drive URL
for (const item of $input.all()) {
  const url = item.json["Motion Video Link"] || ""; // Replace with your field name

  // Regex to capture the ID after 'id=' or within the '/d/ID/view' format
  const regex = /(?:id=|\/d\/)([a-zA-Z0-9_-]+)/;
  const match = url.match(regex);

  item.json.driveFileId = match ? match[1] : null;
}

return $input.all();

for (const item of $input.all()) {
  // 1. Get the duration from the existing metadata (if it exists)
  const durationMillis = item.json.videoMediaMetadata?.durationMillis;

  if (durationMillis) {
    // 2. Add the durationSeconds field while keeping all other fields
    item.json.durationSeconds = parseFloat((durationMillis / 1000).toFixed(2));
  } else {
    // 3. Add fallback values if metadata isn't ready
    item.json.durationSeconds = 0; // Better for math than a string
    item.json._processingStatus = "Pending";
    item.json._note = "Google may still be processing this video's metadata.";
  }
}

// 4. Return the full array of items with all original fields + new fields
return $input.all();

// 1. Get the target duration from the previous node
const MAX_DURATION = $('Get row(s) in sheet').first().json['Total Time of Reel(Secs)'] || 20;

const allInputItems = $input.all();
const finalOutput = [];

let totalRunningDuration = 0; // The continuous total across all groups
let currentGroupItems = [];
let currentGroupTime = 0;
let groupCounter = 1;

// 2. Iterate through items to form groups
for (const item of allInputItems) {
  const duration = item.json.durationSeconds || 0;

  // Add item to the current forming group
  currentGroupItems.push(item.json);
  currentGroupTime += duration;

  // CLUBBING RULE: If group reaches 3 seconds, "seal" it
  if (currentGroupTime >= 3) {
    totalRunningDuration += currentGroupTime;

    finalOutput.push({
      group_id: `group_${groupCounter}`,
      group_duration: parseFloat(currentGroupTime.toFixed(2)),
      running_duration: parseFloat(totalRunningDuration.toFixed(2)), // Cumulative total
      items: currentGroupItems
    });

    // Reset group trackers
    currentGroupItems = [];
    currentGroupTime = 0;
    groupCounter++;
  }

  // TOTAL DURATION RULE: Ensure total is AT LEAST MAX_DURATION
  if (totalRunningDuration >= MAX_DURATION && currentGroupTime === 0) {
    break;
  }
}

// 3. Cleanup: Catch any remaining items if we haven't hit the target yet
if (currentGroupItems.length > 0 && totalRunningDuration < MAX_DURATION) {
    totalRunningDuration += currentGroupTime;
    finalOutput.push({
      group_id: `group_${groupCounter}`,
      group_duration: parseFloat(currentGroupTime.toFixed(2)),
      running_duration: parseFloat(totalRunningDuration.toFixed(2)),
      items: currentGroupItems
    });
}

return finalOutput;

// 1. Define your Seed
// You can hardcode this, or use a value from a previous node like:
// const seed = $('Get Settings').first().json.seedValue;
const seed = 999; 

// 2. Mulberry32 Seeded Random Generator Function
function seededRandom(a) {
    return function() {
      let t = a += 0x6D2B79F5;
      t = Math.imul(t ^ t >>> 15, t | 1);
      t ^= t + Math.imul(t ^ t >>> 7, t | 61);
      return ((t ^ t >>> 14) >>> 0) / 4294967296;
    }
}

const randomGen = seededRandom(seed);

// 3. Get all input items
let items = $input.all();

/**
 * 4. Fisher-Yates Shuffle Algorithm (Deterministic)
 * We use the seeded random instead of Math.random()
 */
for (let i = items.length - 1; i > 0; i--) {
    const j = Math.floor(randomGen() * (i + 1));
    // Swap elements
    [items[i], items[j]] = [items[j], items[i]];
}

// 5. Return the shuffled items
return items;
